solution_code:
#include <iostream>
#include <stdexcept>

int safe_divide(int a, int b) {
    if (b == 0)
        throw std::runtime_error("division by zero");
    return a / b;
}

int main() {
    int a, b;
    std::cin >> a >> b;

    try {
        int result = safe_divide(a, b);
        std::cout << "Result: " << result << "\n";
    } catch (const std::runtime_error& e) {
        std::cout << "Error: division by zero\n";
    }

    return 0;
}

