solution_code:
#include <iostream>
#include <stdexcept>

void add_positive(int val, int& total) {
    if (val < 0)
        throw std::runtime_error("negative value");
    total += val;
}

int main() {
    int n;
    std::cin >> n;

    int total = 0;
    try {
        for (int i = 0; i < n; ++i) {
            int x;
            std::cin >> x;
            add_positive(x, total);
        }
        std::cout << "Sum: " << total << "\n";
    } catch (const std::runtime_error&) {
        std::cout << "Stopped at negative. Partial sum: " << total << "\n";
    }

    return 0;
}
